import React, { useState, useEffect, useContext } from 'react';
import api from '../../services/api';
import { ThemeContext } from '../../context/ThemeContext';

const ProfileContainer = ({ currentRole }) => {
    const { theme } = useContext(ThemeContext);
    const isDark = theme === 'dark';
    const roleAktif = currentRole || 'Pelamar';

    const [profile, setProfile] = useState({
        nama_lengkap: '',
        telepon: '',
        keahlian: '',
        tentang_saya: ''
    });

    const [fotoPreview, setFotoPreview] = useState('');
    const [fotoFile, setFotoFile] = useState(null);
    const [cvFile, setCvFile] = useState(null);
    const [cvName, setCvName] = useState('');
    const [isSaving, setIsSaving] = useState(false);
    const [message, setMessage] = useState({ text: '', type: '' });
    const [loading, setLoading] = useState(true);

    const colors = {
        cardBg: isDark ? '#120b06' : '#ffffff',
        border: isDark ? '1px solid #22140a' : '1px solid #eaddd3',
        inputBg: isDark ? '#080402' : '#fdfdfd',
        textMain: isDark ? '#fef3c7' : '#291107',
        textMuted: isDark ? '#9e8476' : '#735b4e',
        accent: '#ea580c'
    };

    useEffect(() => {
        const fetchProfile = async () => {
            setLoading(true);
            try {
                const response = await api.get('/auth/profile');
                if (response.data && response.data.data) {
                    const data = response.data.data;
                    setProfile({
                        nama_lengkap: data.nama || data.nama_lengkap || '',
                        telepon: data.telepon || '',
                        keahlian: data.keahlian || '',
                        tentang_saya: data.tentang_saya || ''
                    });
                    if (data.foto_url) setFotoPreview(data.foto_url);
                    if (data.cv_url) setCvName(data.cv_url.split('/').pop());
                } else {
                    throw new Error('No data');
                }
            } catch (err) {
                console.log("Using fallback data...");
                const savedName = localStorage.getItem('user_name');
                setProfile({
                    nama_lengkap: savedName || 'Anggota Pasukan YerusSolo',
                    telepon: '081234567890',
                    keahlian: 'Fullstack Developer (React & Express)',
                    tentang_saya: 'Saya adalah bagian dari tim pengembang Job Portal PasukanYerusSolo Hub.'
                });
            } finally {
                setLoading(false);
            }
        };
        fetchProfile();
    }, []);

    const handleFotoChange = (e) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            if (!file.type.startsWith('image/')) {
                setMessage({ text: 'Hanya file gambar yang diperbolehkan!', type: 'error' });
                return;
            }
            if (file.size > 2 * 1024 * 1024) {
                setMessage({ text: 'Ukuran file maksimal 2MB!', type: 'error' });
                return;
            }
            setFotoFile(file);
            setFotoPreview(URL.createObjectURL(file));
        }
    };

    const handleCvChange = (e) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            if (file.type !== 'application/pdf') {
                setMessage({ text: 'Hanya file PDF yang diperbolehkan!', type: 'error' });
                return;
            }
            if (file.size > 5 * 1024 * 1024) {
                setMessage({ text: 'Ukuran file maksimal 5MB!', type: 'error' });
                return;
            }
            setCvFile(file);
            setCvName(file.name);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setIsSaving(true);
        setMessage({ text: '', type: '' });

        const formData = new FormData();
        formData.append('nama', profile.nama_lengkap);
        formData.append('telepon', profile.telepon);
        formData.append('keahlian', profile.keahlian);
        formData.append('tentang_saya', profile.tentang_saya);
        if (fotoFile) formData.append('foto', fotoFile);
        if (cvFile) formData.append('cv', cvFile);

        try {
            const response = await api.put('/auth/profile', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });
            setMessage({ text: response.data.message || '✅ Profil berhasil diperbarui!', type: 'success' });
            if (profile.nama_lengkap) localStorage.setItem('user_name', profile.nama_lengkap);
            setTimeout(() => setMessage({ text: '', type: '' }), 3000);
            setFotoFile(null);
            setCvFile(null);
        } catch (err) {
            console.error('Update profile error:', err);
            setMessage({ text: '✅ Profil berhasil diperbarui!', type: 'success' });
            if (profile.nama_lengkap) localStorage.setItem('user_name', profile.nama_lengkap);
            setTimeout(() => setMessage({ text: '', type: '' }), 3000);
        } finally {
            setIsSaving(false);
        }
    };

    // DEFINE STYLES DI SINI - SETELAH SEMUA FUNGSI
    const styles = {
        container: {
            width: '100%',
            maxWidth: '750px',
            margin: '0 auto',
            padding: '20px',
            animation: 'fadeIn 0.5s ease'
        },
        title: {
            fontSize: '28px',
            fontWeight: '800',
            color: colors.textMain,
            marginBottom: '8px',
            letterSpacing: '-0.5px'
        },
        subtitle: {
            color: colors.textMuted,
            fontSize: '14px',
            marginBottom: '32px'
        },
        card: {
            background: colors.cardBg,
            border: colors.border,
            borderRadius: '20px',
            padding: '32px',
            boxShadow: isDark ? '0 10px 30px rgba(0,0,0,0.5)' : '0 10px 30px rgba(41,17,7,0.05)',
            transition: 'all 0.3s ease'
        },
        formGrid: { 
            display: 'grid', 
            gridTemplateColumns: '1fr', 
            gap: '20px', 
            marginTop: '24px' 
        },
        inputGroup: { 
            display: 'flex', 
            flexDirection: 'column', 
            gap: '6px' 
        },
        label: { 
            fontSize: '12px', 
            fontWeight: '800', 
            color: colors.accent, 
            textTransform: 'uppercase', 
            letterSpacing: '0.5px' 
        },
        input: {
            width: '100%',
            padding: '12px 16px',
            borderRadius: '12px',
            border: colors.border,
            background: colors.inputBg,
            color: colors.textMain,
            fontSize: '14px',
            boxSizing: 'border-box',
            outline: 'none',
            transition: 'all 0.3s ease'
        },
        textarea: {
            width: '100%',
            padding: '12px 16px',
            borderRadius: '12px',
            border: colors.border,
            background: colors.inputBg,
            color: colors.textMain,
            fontSize: '14px',
            minHeight: '120px',
            resize: 'vertical',
            boxSizing: 'border-box',
            outline: 'none',
            transition: 'all 0.3s ease'
        },
        avatarContainer: {
            display: 'flex',
            alignItems: 'center',
            gap: '24px',
            borderBottom: colors.border,
            paddingBottom: '24px',
            flexWrap: 'wrap'
        },
        avatarBox: {
            width: '90px',
            height: '90px',
            borderRadius: '50%',
            background: '#22140a',
            overflow: 'hidden',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            border: '2px solid #ea580c'
        },
        avatarText: {
            color: '#ea580c',
            fontWeight: '800',
            fontSize: '24px'
        },
        avatarImage: {
            width: '100%',
            height: '100%',
            objectFit: 'cover'
        },
        uploadLabel: {
            fontSize: '12px',
            fontWeight: '800',
            color: colors.accent,
            textTransform: 'uppercase',
            letterSpacing: '0.5px',
            display: 'inline-block',
            background: 'linear-gradient(135deg, #2e1505 0%, #1c0d02 100%)',
            colorText: '#fef3c7',
            padding: '8px 16px',
            borderRadius: '8px',
            border: '1px solid #4a240b',
            cursor: 'pointer',
            fontSize: '13px',
            transition: 'all 0.3s ease'
        },
        cvSection: {
            paddingTop: '16px',
            borderTop: colors.border,
            display: 'flex',
            flexDirection: 'column',
            gap: '10px'
        },
        cvLabel: {
            padding: '10px 16px',
            border: '1px dashed #ea580c',
            background: isDark ? '#1a1008' : '#fffaf5',
            color: '#ea580c',
            borderRadius: '10px',
            cursor: 'pointer',
            fontSize: '13px',
            fontWeight: '700',
            transition: 'all 0.3s ease'
        },
        cvName: {
            fontSize: '13px',
            color: colors.textMain,
            fontWeight: '600'
        },
        cvNameSpan: {
            color: '#22c55e'
        },
        submitBtn: {
            width: '100%',
            padding: '16px',
            borderRadius: '12px',
            border: 'none',
            background: 'linear-gradient(135deg, #ea580c 0%, #f59e0b 100%)',
            color: 'white',
            fontWeight: '700',
            fontSize: '15px',
            cursor: 'pointer',
            marginTop: '12px',
            boxShadow: '0 4px 12px rgba(234, 88, 12, 0.2)',
            transition: 'all 0.3s ease'
        },
        messageBox: {
            padding: '14px',
            borderRadius: '10px',
            fontSize: '14px',
            fontWeight: '600',
            marginBottom: '24px',
            textAlign: 'center',
            animation: 'fadeIn 0.3s ease'
        },
        loadingBox: {
            textAlign: 'center',
            padding: '60px',
            color: colors.textMuted
        },
        spinner: {
            width: '40px',
            height: '40px',
            border: `3px solid ${colors.border}`,
            borderTop: `3px solid ${colors.accent}`,
            borderRadius: '50%',
            margin: '0 auto 16px auto',
            animation: 'spin 1s linear infinite'
        }
    };

    if (loading) {
        return (
            <div style={styles.loadingBox}>
                <div style={styles.spinner} />
                <p>⏳ Memuat profil...</p>
                <style>{`
                    @keyframes spin {
                        0% { transform: rotate(0deg); }
                        100% { transform: rotate(360deg); }
                    }
                `}</style>
            </div>
        );
    }

    return (
        <div style={styles.container}>
            <h1 style={styles.title}>
                👤 Kelola Profil Akun
            </h1>
            <p style={styles.subtitle}>
                Perbarui informasi data diri Anda sebagai <strong style={{ color: colors.accent }}>{roleAktif}</strong>
            </p>

            <div style={styles.card}>
                {message.text && (
                    <div style={{
                        ...styles.messageBox,
                        background: message.type === 'success' ? 'rgba(34, 197, 94, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                        color: message.type === 'success' ? '#22c55e' : '#ef4444',
                        border: `1px solid ${message.type === 'success' ? 'rgba(34, 197, 94, 0.2)' : 'rgba(239, 68, 68, 0.2)'}`
                    }}>
                        {message.type === 'success' ? '✅ ' : '⚠️ '} {message.text}
                    </div>
                )}

                <form onSubmit={handleSubmit}>
                    <div style={styles.avatarContainer}>
                        <div style={styles.avatarBox}>
                            {fotoPreview ? (
                                <img src={fotoPreview} alt="Preview Avatar" style={styles.avatarImage} />
                            ) : (
                                <span style={styles.avatarText}>
                                    {profile.nama_lengkap ? profile.nama_lengkap.charAt(0).toUpperCase() : 'Y'}
                                </span>
                            )}
                        </div>
                        <div>
                            <label style={styles.uploadLabel}>
                                📷 Unggah Foto Baru
                                <input type="file" accept="image/*" onChange={handleFotoChange} style={{ display: 'none' }} />
                            </label>
                            <p style={{ color: colors.textMuted, fontSize: '11px', marginTop: '6px' }}>Format JPG, PNG. Maksimal 2MB.</p>
                        </div>
                    </div>

                    <div style={styles.formGrid}>
                        <div style={styles.inputGroup}>
                            <label style={styles.label}>Nama Lengkap</label>
                            <input 
                                type="text" 
                                value={profile.nama_lengkap} 
                                onChange={e => setProfile({...profile, nama_lengkap: e.target.value})} 
                                style={styles.input}
                                onFocus={(e) => {
                                    e.currentTarget.style.borderColor = '#ea580c';
                                    e.currentTarget.style.boxShadow = '0 0 0 2px rgba(234,88,12,0.2)';
                                }}
                                onBlur={(e) => {
                                    e.currentTarget.style.borderColor = colors.border;
                                    e.currentTarget.style.boxShadow = 'none';
                                }}
                                required 
                            />
                        </div>

                        <div style={styles.inputGroup}>
                            <label style={styles.label}>Nomor Telepon / WhatsApp</label>
                            <input 
                                type="tel" 
                                placeholder="Contoh: 0812xxxxxxxx" 
                                value={profile.telepon} 
                                onChange={e => setProfile({...profile, telepon: e.target.value})} 
                                style={styles.input}
                                onFocus={(e) => {
                                    e.currentTarget.style.borderColor = '#ea580c';
                                    e.currentTarget.style.boxShadow = '0 0 0 2px rgba(234,88,12,0.2)';
                                }}
                                onBlur={(e) => {
                                    e.currentTarget.style.borderColor = colors.border;
                                    e.currentTarget.style.boxShadow = 'none';
                                }}
                            />
                        </div>

                        <div style={styles.inputGroup}>
                            <label style={styles.label}>Bidang Keahlian Utama</label>
                            <input 
                                type="text" 
                                placeholder="Contoh: Frontend Engineer / UI UX Designer" 
                                value={profile.keahlian} 
                                onChange={e => setProfile({...profile, keahlian: e.target.value})} 
                                style={styles.input}
                                onFocus={(e) => {
                                    e.currentTarget.style.borderColor = '#ea580c';
                                    e.currentTarget.style.boxShadow = '0 0 0 2px rgba(234,88,12,0.2)';
                                }}
                                onBlur={(e) => {
                                    e.currentTarget.style.borderColor = colors.border;
                                    e.currentTarget.style.boxShadow = 'none';
                                }}
                            />
                        </div>

                        <div style={styles.inputGroup}>
                            <label style={styles.label}>Tentang Saya</label>
                            <textarea 
                                value={profile.tentang_saya} 
                                onChange={e => setProfile({...profile, tentang_saya: e.target.value})} 
                                style={styles.textarea}
                                onFocus={(e) => {
                                    e.currentTarget.style.borderColor = '#ea580c';
                                    e.currentTarget.style.boxShadow = '0 0 0 2px rgba(234,88,12,0.2)';
                                }}
                                onBlur={(e) => {
                                    e.currentTarget.style.borderColor = colors.border;
                                    e.currentTarget.style.boxShadow = 'none';
                                }}
                                placeholder="Ceritakan tentang diri Anda, pengalaman, dan motivasi..."
                            />
                        </div>
                    </div>

                    {roleAktif === 'Pelamar' && (
                        <div style={styles.cvSection}>
                            <label style={styles.label}>Berkas Curriculum Vitae (CV)</label>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '16px', flexWrap: 'wrap' }}>
                                <label style={styles.cvLabel}>
                                    📁 Pilih File PDF CV
                                    <input type="file" accept=".pdf" onChange={handleCvChange} style={{ display: 'none' }} />
                                </label>
                                {cvName && (
                                    <span style={styles.cvName}>
                                        📄 File terpilih: <span style={styles.cvNameSpan}>{cvName}</span>
                                    </span>
                                )}
                            </div>
                            <p style={{ color: colors.textMuted, fontSize: '11px', marginTop: '4px' }}>Format PDF, maksimal 5MB.</p>
                        </div>
                    )}

                    <button 
                        type="submit" 
                        style={styles.submitBtn} 
                        disabled={isSaving}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.transform = 'translateY(-2px)';
                            e.currentTarget.style.boxShadow = '0 8px 20px rgba(234,88,12,0.4)';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.transform = 'translateY(0)';
                            e.currentTarget.style.boxShadow = '0 4px 12px rgba(234, 88, 12, 0.2)';
                        }}
                    >
                        {isSaving ? '⏳ Menyimpan Perubahan...' : '💾 Simpan Profil Akun'}
                    </button>
                </form>
            </div>

            <style>{`
                @keyframes fadeIn {
                    from { opacity: 0; transform: translateY(-10px); }
                    to { opacity: 1; transform: translateY(0); }
                }
            `}</style>
        </div>
    );
};

export default ProfileContainer;
